INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (100, "2024/03/31 12:00:00", 1, 129901, 10.85, 100, 24, 7, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "訓練成功、おめでとうございます\n褒めるべき時にはしっかり褒めるのも\n教官の務めですものね。それとも、\n罵られる方が好みですか？　クスクス", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (101, "2024/03/31 12:00:00", 1, 129901, 11.15, 101, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "厳しい訓練も、終わってみれば\n短く感じるものですわね。\n正直、私は暴れ足りないくらい…\nいえ、何でもありませんわ。クスクス", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (102, "2024/03/31 12:00:00", 7, 129901, 6.4, 102, 24, 5, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "行く手を阻む忌々しい邪魔者を\n蹴散らして、見事ゴールイン…！\nまるで私とあのおかたの人生を\n象徴するような道のりでした…", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (103, "2024/03/31 12:00:00", 3, 129901, 0.0, 103, 24, 3, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "まったくもって不甲斐ない結果です\nしかし、挽回の機会はまだありますわ\n次はゴミ虫の地位から脱却できるよう\n死力を尽くしなさい。いいですね？", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (104, "2024/03/31 12:00:00", 2, 129901, 2.43, 104, 24, 8, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "クスクス…ああご心配なさらず\nなんとも情けない成績を残す輩には\nどんな罰が相応しいか、考えている\nだけですので…クスクスクス", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (105, "2024/03/31 12:00:00", 4, 129901, 9.08, 105, 24, 3, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "私が教官として認められなければ、\nあのおかたを失望させてしまう…\nそれだけはあってはなりません\nあなた方も、わかっていますわね？", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (106, "2024/03/31 12:00:00", 6, 129901, 0.0, 106, 24, 6, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "まずまずの結果ではありますが、\nこの程度で満足してもらっては\n困りますわ。エリコ班の一員として、\nより高みを目指していただきますので", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (107, "2024/03/31 12:00:00", 3, 129901, 10.6, 107, 24, 8, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "私の指導を受けながら、この結果は…\nもっと真剣に考えねばなりませんね\nあなた方が怠けずにいるには、\nどんなしつけが必要かを…クスクス", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (108, "2024/03/31 12:00:00", 6, 129901, 7.54, 108, 24, 4, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "ひとまず訓練をこなしたご褒美か、\n実力を出しきれたとは言えない罰か…\nみなさんにどちらを与えるべきか\n少し悩む結果ですわね", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (109, "2024/03/31 12:00:00", 2, 129901, 11.5, 109, 24, 7, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "なかなかいい戦いぶりでしたわ\nこれもあなた方の頑張りと、何より\n優秀な教官である私の教育の賜物\nそうですわね？　クスクスクス…", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (110, "2024/03/31 12:00:00", 2, 129901, 8.83, 110, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "これだけ進めたのならば合格点ですわ\nでも、もっと高みを目指したいと\n思っているのなら…さらなる訓練にも\n付き合って差し上げましょう", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (111, "2024/03/31 12:00:00", 1, 129901, 6.68, 111, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "未熟で頼りなかったあなた方が、\n見違えるように成長しました\nなるほど…これこそが、教官冥利に\n尽きるという気持ちなのですね", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (112, "2024/03/31 12:00:00", 6, 129901, 8.8, 112, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "まさかあなた方が、私の予想すら\n超える力を発揮するとは…驚きました\nもはやゴミ虫などではありません\n一人前の騎士として胸を張りなさい", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (113, "2024/03/31 12:00:00", 2, 129901, 8.9, 113, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "クスクス、見事な働きです\nみなさんならできると信じていました\n他でもない私の指導を受けた、\nエリコ班の優秀な新兵なのですから", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (114, "2024/03/31 12:00:00", 2, 129901, 3.7, 114, 24, 5, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "なんてすばらしい成績…！\n今日という日は『あのおかたを想い\nエリコが限界を超えた記念日』として\n歴史に刻まれることでしょう…！", "エリコ");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (200, "2024/03/31 12:00:00", 1, 129801, 7.6, 200, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "よし、いい訓練になったな\nおまえたちもよく動けてたし、\nちゃんと成長できてると思うぜ\nその調子で頑張れよっ", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (201, "2024/03/31 12:00:00", 2, 129801, 2.25, 201, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "ひとまずゴールおめでとう！\nでも、努力は継続してこそだからな\nおまえたちにやる気があるなら、\n何度だって付き合ってやるよ", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (202, "2024/03/31 12:00:00", 2, 129801, 3.28, 202, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "行軍訓練はこれにて完了！\n…なーんて思ってないよな？\n学んだことが体に染みつくまで\n地道に繰り返すのが練習ってもんさ", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (203, "2024/03/31 12:00:00", 4, 129801, 2.98, 203, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "みんなに無理をさせちまったか…\nでもこれで諦めることはないぜ\n次はきっとうまくいく。そう信じて\n鍛え続ければ、道は開けるはずだ！", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (204, "2024/03/31 12:00:00", 4, 129801, 3.0, 204, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "こいつは悔しい結果だな…\nま、反省点はいろいろあったし\nひとつずつ乗り越えていこう\nあたしたちで力を合わせて、なっ！", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (205, "2024/03/31 12:00:00", 1, 129801, 10.3, 205, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "おまえたちはまだ未熟な訓練兵、\n失敗を必要以上に悔やむことはねえよ\nでも実戦じゃこうはいかないからな\n次は気合を入れ直していけよっ！", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (206, "2024/03/31 12:00:00", 6, 129801, 2.93, 206, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "これがおまえたちの全力？\nいやいや、そんなはずはないよなっ\nおまえらならもっと強くなれる！\nあたしが言うんだ、間違いないぜ！", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (207, "2024/03/31 12:00:00", 3, 129801, 9.3, 207, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "おまえたちの実力を考えりゃ、\nベストを尽くせたとは言えない成績だ\nなら、次やるべきことも決まってる\n気持ちを切り替えて、鍛え直すんだ！", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (208, "2024/03/31 12:00:00", 4, 129801, 6.9, 208, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "まだまだ課題がある内容だったな～\n無駄な動き、判断の遅れ…\nそういうのをしっかり直していけば、\n記録ももっと伸びるはずだっ", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (209, "2024/03/31 12:00:00", 2, 129801, 0.0, 209, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "ここまでいけりゃ、合格点！\nむしろ、最初の頼りなさを思えば\nすげえ成長してるんじゃねえか？\n胸を張れる結果だと思うぜっ！", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (210, "2024/03/31 12:00:00", 1, 129801, 5.95, 210, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "なかなかハードな訓練だったけど、\nみんなしっかりついてこられたな\n地道に続けた基礎トレの成果が\n形になってる、その証だぜっ", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (211, "2024/03/31 12:00:00", 2, 129801, 6.73, 211, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "今回の訓練もよく頑張ったな！\nしっかり休んで次に備えろよ！\nなんつーか、教え子が成長してくのを\n見るのは楽しいもんだな…", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (212, "2024/03/31 12:00:00", 2, 129801, 0.0, 212, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "おまえら、すげえじゃねえか！\nこれならもう、ひよっこ新兵なんて\n言えねえな。きっと騎士団でも\n大活躍間違いなしだぜ！", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (213, "2024/03/31 12:00:00", 1, 129801, 6.65, 213, 24, 2, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "敵との戦い方、状況判断の正確さ\n何より根性…どれも最高だったぞ！\nうかうかしてたら、教官のあたしまで\n追い抜かれちまうかもな…へへっ", "マコト");
INSERT INTO `v1_0ddaf0975825562526a933d92414f08ad99380825846c4b431c4590067ad88c3` VALUES (214, "2024/03/31 12:00:00", 6, 129801, 3.05, 214, 24, 1, 0.0, "2030/12/17 14:59:59", 0.0, 10142, "あたしの指導が良かった？\nいやいや、ここまで強くなれたのは、\n他でもないおまえたち自身が努力した\nおかげだよ。改めて…おめでとうっ！", "マコト");
